INSERT INTO rag.cach_thuc_thuc_hien VALUES (33, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Trực tiếp tại cơ quan quản lý căn cước của Bộ Công an (Trung tâm dữ liệu quốc gia về dân cư, Cục Cảnh sát quản lý hành chính về trật tự xã hội, Bộ Công an). - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: - 07 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số chưa có trong Cơ sở dữ liệu quốc gia về dân cư.', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (34, 'Trực tiếp', '03 Ngày làm việc', '', '- 03 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số đã có trong Cơ sở dữ liệu quốc gia về dân cư', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (35, 'Trực tuyến', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: - 07 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số chưa có trong Cơ sở dữ liệu quốc gia về dân cư.', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (36, 'Trực tuyến', '03 Ngày làm việc', '', '- 03 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số đã có trong Cơ sở dữ liệu quốc gia về dân cư', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (37, 'Dịch vụ bưu chính', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Nộp hồ sơ qua dịch vụ bưu chính (nếu có). - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: - 07 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số chưa có trong Cơ sở dữ liệu quốc gia về dân cư.', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (38, 'Dịch vụ bưu chính', '03 Ngày làm việc', '', '- 03 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số đã có trong Cơ sở dữ liệu quốc gia về dân cư', '1.000466');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (39, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : 70.000 Đồng - Cấp lại thẻ căn cước đối với các trường hợp quy định tại khoản 2 Điều 24 Luật Căn cước: 70.000 đồng/thẻ căn cước. Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư số 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Trực tiếp tại cơ quan quản lý căn cước của Bộ Công an (Trung tâm dữ liệu quốc gia về dân cư, Cục Cảnh sát quản lý hành chính về trật tự xã hội, Bộ Công an). - Cấp lưu động tại tại xã, phường, thị trấn, cơ quan, đơn vị hoặc tại chỗ ở của công dân trong trường hợp cần thiết. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.000757');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (40, 'Trực tuyến', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.000757');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (51, 'Trực tuyến', '05 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp hồ sơ trực tuyến qua Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an. Không quá 05 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (41, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : 50.000 Đồng Luật Căn cước: 50.000 đồng/thẻ căn cước; Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư số 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Trực tiếp tại cơ quan quản lý căn cước của Bộ Công an (Trung tâm dữ liệu quốc gia về dân cư, Cục Cảnh sát quản lý hành chính về trật tự xã hội, Bộ Công an). - Cấp lưu động tại tại xã, phường, đặc khu, cơ quan, đơn vị hoặc tại chỗ ở của công dân trong trường hợp cần thiết. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: Không quá 07 ngày làm việc.', '1.000889');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (42, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Trực tiếp tại cơ quan quản lý căn cước của Bộ Công an (Trung tâm dữ liệu quốc gia về dân cư, Cục Cảnh sát quản lý hành chính về trật tự xã hội, Bộ Công an). - Cấp lưu động tại tại xã, phường, thị trấn, cơ quan, đơn vị hoặc tại chỗ ở của công dân trong trường hợp cần thiết. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.001247');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (43, 'Trực tiếp', '01 Ngày làm việc', '', 'Trực tiếp nộp hồ sơ tại cơ quan quản lý xuất nhập cảnh Công an cấp tỉnh. 01 ngày làm việc kể từ khi nhận đơn báo mất, cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn.', '1.001445');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (44, 'Trực tuyến', '1 Ngày làm việc', '', 'Nộp hồ sơ trực tuyến qua Cổng Dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an. 01 ngày làm việc kể từ khi nhận đơn báo mất, cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn.', '1.001445');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (45, 'Dịch vụ bưu chính', '01 Ngày làm việc', '', 'Nộp hồ sơ thông qua qua dịch vụ bưu chính. 01 ngày làm việc kể từ khi nhận đơn báo mất, cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn.', '1.001445');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (46, 'Trực tiếp', '08 Ngày làm việc', 'Phí : 160000 Đồng + 160.000/hộ chiếu, trường hợp cấp lại do bị hư hỏng hoặc bị mất: 320.000đ/hộ chiếu (áp dụng đến hết ngày 31/12/2023 theo Thông tư số 44/2023/TT-BTC ngày 29/6/2023 của Bộ tài chính).  Phí : 200000 Đồng 200.000đ/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp hồ sơ trực tiếp tại trụ sở Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh (có thể khai tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước qua các cổng cung cấp dịch vụ công trực tuyến trước khi đến nộp hồ sơ trực tuyến).', '1.001456');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (47, 'Trực tuyến', '08 Ngày làm việc', 'Phí : 160000 Đồng + 160.000/hộ chiếu, trường hợp cấp lại do bị hư hỏng hoặc bị mất: 320.000đ/hộ chiếu (áp dụng đến hết ngày 31/12/2023 theo Thông tư số 44/2023/TT-BTC ngày 29/6/2023 của Bộ tài chính).  Phí : 200000 Đồng 200.000đ/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp hồ sơ trực tuyến qua Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an.', '1.001456');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (48, 'Dịch vụ bưu chính', '08 Ngày làm việc', 'Phí : 160000 Đồng + 160.000/hộ chiếu, trường hợp cấp lại do bị hư hỏng hoặc bị mất: 320.000đ/hộ chiếu (áp dụng đến hết ngày 31/12/2023 theo Thông tư số 44/2023/TT-BTC ngày 29/6/2023 của Bộ tài chính).  Phí : 200000 Đồng 200.000đ/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu', 'nộp bổ sung hồ sơ qua dịch vụ bưu chính công ích theo thông báo của Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh trên Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an (nếu có).', '1.001456');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (49, 'Trực tiếp', '05 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp hồ sơ trực tiếp tại trụ sở Cục Quản lý xuất nhập cảnh (có thể khai tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước qua các cổng cung cấp dịch vụ công trực tuyến trước khi đến nộp hồ sơ trực tuyến). Không quá 05 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (50, 'Trực tiếp', '03 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'Không quá 03 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định đối với các trường hợp quy định tại khoản 4 Điều 15 Luật xuất cảnh, nhập cảnh của công dân Việt Nam. Có thể khai tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước qua các cổng cung cấp dịch vụ công trực tuyến, sau đó trực tiếp nộp hồ sơ và nhận kết quả hoặc đề nghị nhận kết quả qua dịch vụ bưu chính.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (52, 'Trực tuyến', '03 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp hồ sơ trực tuyến qua Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an. Không quá 03 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định đối với các trường hợp quy định tại khoản 4 Điều 15 Luật xuất cảnh, nhập cảnh của công dân Việt Nam. Có thể khai tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước qua các cổng cung cấp dịch vụ công trực tuyến, sau đó trực tiếp nộp hồ sơ và nhận kết quả hoặc đề nghị nhận kết quả qua dịch vụ bưu chính.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (53, 'Dịch vụ bưu chính', '05 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp bổ sung hồ sơ qua dịch vụ bưu chính công ích theo thông báo của Cục Quản lý xuất nhập cảnh trên Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an (nếu có). Không quá 05 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (54, 'Dịch vụ bưu chính', '03 Ngày làm việc', 'Phí : 200000 Đồng 200.000 đồng/ hộ chiếu. Trường hợp cấp lại do bị hỏng hoặc bị mất: 400.000đ/hộ chiếu (Thông tư số 25/2021/TT-BTC ngày 07/4/2021 của Bộ Tài chính).', 'nộp bổ sung hồ sơ qua dịch vụ bưu chính công ích theo thông báo của Cục Quản lý xuất nhập cảnh trên Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an (nếu có). Không quá 03 ngày làm việc kể từ ngày nhận đầy đủ hồ sơ theo quy định đối với các trường hợp quy định tại khoản 4 Điều 15 Luật xuất cảnh, nhập cảnh của công dân Việt Nam. Có thể khai tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước qua các cổng cung cấp dịch vụ công trực tuyến, sau đó trực tiếp nộp hồ sơ và nhận kết quả hoặc đề nghị nhận kết quả qua dịch vụ bưu chính.', '1.001471');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (55, 'Trực tiếp', '03 Ngày làm việc', 'Phí : 10.000 Đồng - Gia hạn tạm trú theo danh sách: + Trường hợp công dân nộp hồ sơ trực tiếp thu 10.000 đồng/người/lần đăng ký;  Phí : 15.000 Đồng - Gia hạn tạm trú (cá nhân, hộ gia đình): + Trường hợp công dân nộp hồ sơ trực tiếp thu 15.000 đồng/lần đăng ký;  Phí : Miễn phí Đồng - Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 của Bộ Tài chính quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, Cơ sở dữ liệu chuyên ngành mà đã được kết nối với Cơ sở dữ liệu quốc gia về dân cư.', '- Nộp hồ sơ trực tiếp tại Công an cấp xã. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.002755');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (56, 'Trực tuyến', '03 Ngày làm việc', 'Phí : 5.000 Đồng - Gia hạn tạm trú theo danh sách: + Trường hợp công dân nộp hồ sơ qua cổng dịch vụ công trực tuyến thu 5.000 đồng/người/lần đăng ký.  Phí : 7.000 Đồng - Gia hạn tạm trú (cá nhân, hộ gia đình): + Trường hợp công dân nộp hồ sơ qua cổng dịch vụ công trực tuyến thu 7.000 đồng/lần đăng ký.  Phí : Miễn phí Đồng Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 của Bộ Tài chính quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, Cơ sở dữ liệu chuyên ngành mà đã được kết nối với Cơ sở dữ liệu quốc gia về dân cư.', '- Nộp hồ sơ trực tuyến qua các cổng cung cấp dịch vụ công trực tuyến như: Trực tuyến qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, ứng dụng VNeID hoặc dịch vụ công trực tuyến khác theo quy định của pháp luật. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.002755');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (57, 'Trực tuyến', '01 Ngày làm việc', '', '- Trường hợp thuộc quy định tại điểm c, điểm d khoản 1 Điều 31 Luật Cư trú thì khai báo tạm vắng qua: + Trực tiếp tại cơ quan đăng ký cư trú hoặc tại địa điểm tiếp nhận khai báo tạm vắng do cơ quan đăng ký cư trú quy định; + Số điện thoại hoặc hộp thư điện tử do cơ quan đăng ký cư trú thông báo hoặc niêm yết; + Trang thông tin điện tử của cơ quan đăng ký cư trú hoặc qua các cổng cung cấp dịch vụ công trực tuyến như: Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Cổng dịch vụ công quản lý cư trú; + Ứng dụng trên thiết bị điện tử. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Trong thời gian 01 ngày kể từ khi tiếp nhận đề nghị khai báo tạm vắng của công dân.', '1.003677');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (58, 'Trực tuyến', '02 Ngày làm việc', '', 'trường hợp phức tạp thì có thể kéo dài hơn nhưng không quá 02 ngày làm việc.', '1.003677');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (70, 'Trực tuyến', '01 Ngày làm việc', 'Phí : 0 Đồng', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp huyện thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp huyện, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ trực tuyến qua Cổng Dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an.', '1.010385');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (59, 'Trực tiếp', '03 Ngày làm việc', 'Phí : 10.000 Đồng - Đăng ký tạm trú theo danh sách: + Trường hợp công dân nộp hồ sơ trực tiếp thu 10.000 đồng/người/lần đăng ký;  Phí : 15.000 Đồng Đăng ký tạm trú (cá nhân, hộ gia đình): + Trường hợp công dân nộp hồ sơ trực tiếp thu 15.000 đồng/lần đăng ký;  Phí : Miễn phí Đồng - Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, Cơ sở dữ liệu chuyên ngành mà đã được kết nối với Cơ sở dữ liệu quốc gia về dân cư.', '- Nộp hồ sơ trực tiếp tại Công an cấp xã. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.004194');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (60, 'Trực tuyến', '03 Ngày làm việc', 'Phí : 5.000 Đồng - Đăng ký tạm trú theo danh sách: + Trường hợp công dân nộp hồ sơ qua cổng dịch vụ công trực tuyến thu 5.000 đồng/người/lần đăng ký.  Phí : 7.000 Đồng - Đăng ký tạm trú (cá nhân, hộ gia đình): + Trường hợp công dân nộp hồ sơ qua cổng dịch vụ công trực tuyến thu 7.000 đồng/lần đăng ký.  Phí : Miễn phí Đồng - Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, Cơ sở dữ liệu chuyên ngành mà đã được kết nối với Cơ sở dữ liệu quốc gia về dân cư.', '- Nộp hồ sơ trực tuyến qua các cổng cung cấp dịch vụ công trực tuyến như: Trực tuyến qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, ứng dụng VNeID hoặc dịch vụ công trực tuyến khác theo quy định của pháp luật. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.004194');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (61, 'Trực tiếp', '07 Ngày làm việc', 'Phí : 20.000 Đồng Trường hợp công dân nộp hồ sơ trực tiếp thu 20.000 đồng/lần đăng ký;  Phí : Miễn phí Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú được sửa đổi, bổ sung tại Thông tư số 71/2025/TT-BTC ngày 01/7/2025 của Bộ Tài chính thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, cơ sở', '- Nộp hồ sơ trực tiếp tại Công an cấp xã. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.004222');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (62, 'Trực tuyến', '07 Ngày làm việc', 'Phí : 10.000 Đồng Trường hợp công dân nộp hồ sơ qua cổng dịch vụ công trực tuyến thu 10.000 đồng/lần đăng ký.  Phí : Miễn phí Trường hợp công dân thuộc diện được miễn phí theo quy định tại Điều 4 Thông tư số 75/2022/TT-BTC ngày 22/12/2022 quy định mức thu, chế độ thu, nộp và quản lý lệ phí đăng ký cư trú được sửa đổi, bổ sung tại Thông tư số 71/2025/TT-BTC ngày 01/7/2025 của Bộ Tài chính thì công dân phải xuất trình giấy tờ chứng minh thuộc diện được miễn trừ trường hợp thông tin đã có trong Cơ sở dữ liệu quốc gia về dân cư hoặc Cơ sở dữ liệu quốc gia, cơ sở', '- Nộp hồ sơ trực tuyến qua các cổng cung cấp dịch vụ công trực tuyến như: Trực tuyến qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, ứng dụng VNeID hoặc dịch vụ công trực tuyến khác theo quy định của pháp luật; Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.004222');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (63, 'Trực tiếp', '03 Ngày làm việc', '', 'nộp hồ sơ trực tiếp tại trụ sở Cục Quản lý xuất nhập cảnh. Không quá 03 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010382');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (64, 'Trực tuyến', '03 Ngày làm việc', '', 'nộp hồ sơ trực tuyến qua Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an. Không quá 03 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010382');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (65, 'Dịch vụ bưu chính', '03 Ngày làm việc', '', 'nộp bổ sung hồ sơ qua dịch vụ bưu chính công ích theo thông báo của Cục Quản lý xuất nhập cảnh trên Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an (nếu có). Không quá 03 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010382');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (66, 'Trực tiếp', '05 Ngày làm việc', '', 'nộp hồ sơ trực tiếp tại trụ sở Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh. Không quá 05 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010384');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (67, 'Trực tuyến', '05 Ngày làm việc', '', 'nộp hồ sơ trực tuyến qua Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an. Không quá 05 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010384');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (68, 'Dịch vụ bưu chính', '05 Ngày làm việc', '', 'nộp bổ sung hồ sơ qua dịch vụ bưu chính công ích theo thông báo của Cơ quan Quản lý xuất nhập cảnh Công an cấp tỉnh trên Cổng dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an (nếu có). Không quá 05 ngày làm việc từ ngày nhận đầy đủ hồ sơ theo quy định.', '1.010384');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (69, 'Trực tiếp', '01 Ngày làm việc', 'Phí : 0 Đồng', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp huyện thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp huyện, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Trực tiếp nộp hồ sơ tại trụ sở làm việc của Công an cấp huyện.', '1.010385');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (71, 'Dịch vụ bưu chính', '01 Ngày làm việc', 'Phí : 0 Đồng', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp huyện thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp huyện, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ qua dịch vụ bưu chính.', '1.010385');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (72, 'Trực tiếp', '01 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp xã thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp xã, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Trực tiếp nộp hồ sơ tại trụ sở làm việc của Công an cấp xã.', '1.010386');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (73, 'Trực tuyến', '01 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp xã thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp xã, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ trực tuyến qua Cổng Dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an.', '1.010386');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (74, 'Dịch vụ bưu chính', '01 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Công an cấp xã thông báo bằng văn bản cho người gửi đơn và Cục Quản lý xuất nhập cảnh; trong thời hạn 01 ngày làm việc kể từ ngày nhận được thông báo của Công an cấp xã, Cục Quản lý xuất nhập cảnh thực hiện hủy giá trị sử dụng của hộ chiếu và thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ qua dịch vụ bưu chính.', '1.010386');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (75, 'Trực tiếp', '07 Ngày làm việc', '', '- Trực tiếp tại địa điểm tiếp dân cơ quan quản lý căn cước của Công an cấp tỉnh (Phòng Cảnh sát Quản lý hành chính về trật tự xã hội, Công an các tỉnh, thành phố) hoặc Trung tâm phục vụ hành chính công tỉnh, thành phố (nếu đã triển khai) trong cả nước không phụ thuộc vào nơi cư trú.đề nghị cấp thẻ căn cước. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: Không quá 07 ngày làm việc.', '2.000200');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (76, 'Trực tuyến', '07 Ngày làm việc', '', '- Thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia để đăng ký thời gian, địa điểm làm thủ tục đề nghị cấp thẻ căn cước. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: Không quá 07 ngày làm việc.', '2.000200');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (77, 'Trực tiếp', '01 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Cục Quản lý xuất nhập cảnh hủy giá trị sử dụng hộ chiếu và gửi thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Trực tiếp nộp hồ sơ tại trụ sở làm việc của Cục Quản lý xuất nhập cảnh - Bộ Công an.', '2.000539');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (78, 'Trực tuyến', '1 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Cục Quản lý xuất nhập cảnh hủy giá trị sử dụng hộ chiếu và gửi thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ trực tuyến qua Cổng Dịch vụ công quốc gia hoặc Cổng dịch vụ công Bộ Công an.', '2.000539');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (79, 'Dịch vụ bưu chính', '01 Ngày làm việc', '', '01 ngày làm việc kể từ khi nhận đơn trình báo mất hộ chiếu phổ thông, Cục Quản lý xuất nhập cảnh hủy giá trị sử dụng hộ chiếu và gửi thông báo về việc giải quyết đơn trình báo mất hộ chiếu cho người gửi đơn. Nộp hồ sơ qua dịch vụ bưu chính', '2.000539');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (80, 'Trực tuyến', '0 Giờ', '', '- Thông qua số điện thoại hoặc hộp thư điện tử do cơ quan đăng ký cư trú thông báo hoặc niêm yết; - Thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, ứng dụng VNeID hoặc dịch vụ công trực tuyến khác Tiếp nhận ngay khi công dân thông báo lưu trú.', '2.001159');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (81, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : Đồng Chưa quy định.', '- Trực tiếp tại địa điểm tiếp dân cơ quan quản lý căn cước của Công an cấp tỉnh (Phòng Cảnh sát Quản lý hành chính về trật tự xã hội, Công an các tỉnh, thành phố trực thuộc Trung ương). - Nộp hồ sơ trực tuyến thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia. - Nộp hồ sơ qua dịch vụ bưu chính (nếu có). - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật). Thời hạn giải quyết: 07 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số chưa có trong Cơ sở dữ liệu quốc gia về dân cư.', '2.001178');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (82, 'Trực tiếp', '03 Ngày làm việc', '', 'Thời hạn giải quyết: 03 ngày làm việc đối với trường hợp thông tin số chứng minh nhân dân 09 số đã được cập nhật trong Cơ sở dữ liệu quốc gia về dân cư.', '2.001178');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (83, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : 70.000 Đồng - Cấp lại thẻ căn cước đối với các trường hợp quy định tại khoản 2 Điều 24 Luật Căn cước: 70.000 đồng/thẻ căn cước. Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Trực tiếp tại địa điểm tiếp dân cơ quan quản lý căn cước của Công an cấp tỉnh (Phòng Cảnh sát Quản lý hành chính về trật tự xã hội, Công an các tỉnh, thành phố) trong cả nước không phụ thuộc vào nơi cư trú. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '2.001194');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (84, 'Trực tuyến', '07 Ngày làm việc', 'Lệ phí : 70.000 Đồng - Cấp lại thẻ căn cước đối với các trường hợp quy định tại khoản 2 Điều 24 Luật Căn cước: 70.000 đồng/thẻ căn cước. Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Thực hiện trực tuyến thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '2.001194');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (85, 'Dịch vụ bưu chính', '07 Ngày làm việc', 'Phí : Đồng Trả phí cho đơn vị cung cấp dịch vụ.', 'Trả kết quả qua dịch vụ bưu chính', '2.001194');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (86, 'Trực tiếp', '07 Ngày làm việc', 'Lệ phí : 50.000 Đồng - Cấp đổi thẻ căn cước đối với các trường hợp quy định tại khoản 1 Điều 24 Luật Căn cước: 50.000 đồng/thẻ căn cước; Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Trực tiếp tại địa điểm tiếp dân cơ quan quản lý căn cước của Công an cấp tỉnh (Phòng Cảnh sát Quản lý hành chính về trật tự xã hội, Công an các tỉnh, thành phố) trong cả nước không phụ thuộc vào nơi cư trú. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '2.001195');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (87, 'Trực tuyến', '07 Ngày làm việc', 'Lệ phí : 50.000 Đồng - Cấp đổi thẻ căn cước đối với các trường hợp quy định tại khoản 1 Điều 24 Luật Căn cước: 50.000 đồng/thẻ căn cước; Kể từ ngày 01/01/2025 đến hết ngày 31/12/2025, mức thu lệ phí khi công dân nộp hồ sơ cấp đổi, cấp lại thẻ căn cước theo hình thức trực tuyển bằng 50% mức thu lệ phí quy định. - Kể từ ngày 01/7/2025 đến hết ngày 31/12/2026 mức thu lệ phí cấp đổi, cấp lại thẻ căn cước bằng 50% mức thu nêu trên theo quy định tại Thông tư 64/2025/TT-BTC ngày 30/6/2025 của Bộ Tài chính.', '- Thông qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, Ứng dụng định danh quốc gia để đăng ký thời gian, địa điểm làm thủ tục đề nghị cấp đổi thẻ căn cước tại cơ quan quản lý căn cước của Công an cấp tỉnh trong cả nước không phụ thuộc vào nơi cư trú. - Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '2.001195');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (88, 'Trực tiếp', '02 Ngày làm việc', '', '- Nộp hồ sơ trực tiếp tại Công an cấp xã. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.010028');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (89, 'Trực tuyến', '02 Ngày làm việc', '', '-Nộp hồ sơ trực tuyến qua các cổng cung cấp dịch vụ công trực tuyến như: Trực tuyến qua Cổng dịch vụ công quốc gia, Cổng dịch vụ công Bộ Công an, ứng dụng VNeID hoặc dịch vụ công trực tuyến khác theo quy định của pháp luật. Thời gian tiếp nhận hồ sơ: Giờ hành chính các ngày làm việc từ thứ 2 đến thứ 6 và sáng thứ 7 hàng tuần (trừ các ngày nghỉ lễ, tết theo quy định của pháp luật).', '1.010028');
INSERT INTO rag.cach_thuc_thuc_hien VALUES (90, 'Dịch vụ bưu chính', '02 Ngày làm việc', '', '', '1.010028');


