INSERT INTO rag.thanh_phan_ho_so VALUES (6, 'Bao gồm', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '1.000466');
INSERT INTO rag.thanh_phan_ho_so VALUES (7, 'Bao gồm', 'Giấy chứng minh nhân dân 09 số (nếu có).', '', 'Bản chính: 1Bản sao: 0', '1.000466');
INSERT INTO rag.thanh_phan_ho_so VALUES (8, 'Phiếu này là biểu mẫu điện tử, công dân kê khai đối với trường hợp nộp hồ sơ trực tuyến', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '1.000757');
INSERT INTO rag.thanh_phan_ho_so VALUES (9, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '1.000757');
INSERT INTO rag.thanh_phan_ho_so VALUES (10, 'Trường hợp người đề nghị cấp, cấp đổi, cấp lại thẻ căn cước là người đại diện hợp pháp của người dưới 14 tuổi thì hồ sơ đề nghị cấp, cấp đổi, cấp lại thẻ căn cước phải có giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi.', 'Giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi', '', 'Bản chính: 1Bản sao: 0', '1.000757');
INSERT INTO rag.thanh_phan_ho_so VALUES (11, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '1.000889');
INSERT INTO rag.thanh_phan_ho_so VALUES (12, 'Bao gồm', 'Giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi', '', 'Bản chính: 1Bản sao: 0', '1.000889');
INSERT INTO rag.thanh_phan_ho_so VALUES (13, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '1.001247');
INSERT INTO rag.thanh_phan_ho_so VALUES (14, 'Bao gồm', 'đơn trình báo mất hộ chiếu phổ thông (mẫu TK05) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, có khó khăn trong nhận thức và làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai và ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK05báomấtHC057TK05MỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.001445');
INSERT INTO rag.thanh_phan_ho_so VALUES (15, 'Bao gồm', 'Tờ khai đề nghị cấp hộ chiếu phổ thông ở trong nước (mẫu TK01 dành cho người từ 14 tuổi trở lên; mẫu TK01a dành cho người chưa đủ 14 tuổi) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi theo quy định của Bộ luật Dân sự, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai và ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MauTK01tokhaicapHCPTởtrongnướcTK01MỚI.pdf, https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MauTK01atokhaitrẻemcapHCPTởtrongnướcTK01aMỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (16, 'Bao gồm', 'Ảnh mới chụp không quá 06 tháng, cỡ 4cm x 6cm, mặt nhìn thẳng, đầu để trần, rõ mặt, rõ hai tai, không đeo kính, trang phục lịch sự, phông ảnh nền trắng', '', 'Bản chính: 1Bản sao: 0', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (17, 'Bao gồm', 'Hộ chiếu phổ thông cấp lần gần nhất còn giá trị sử dụng đối với người đã được cấp hộ chiếu; trường hợp hộ chiếu còn giá trị sử dụng bị mất phải kèm đơn báo mất hoặc thông báo về việc đã tiếp nhận đơn của cơ quan có thẩm quyền quy định tại điểm a khoản 2 Điều 28 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam.', '', 'Bản chính: 1Bản sao: 0', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (18, 'Bao gồm', 'Bản sao giấy khai sinh hoặc trích lục giấy khai sinh đối với người chưa đủ 14 tuổi chưa được cấp mã số định danh cá nhân; trường hợp không có bản sao Giấy khai sinh, trích lục khai sinh thì nộp bản chụp và xuất trình bản chính để kiểm tra, đối chiếu.', '', 'Bản chính: 1Bản sao: 1', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (19, 'Bao gồm', 'Bản sao giấy tờ do cơ quan có thẩm quyền của Việt Nam cấp chứng minh người đại diện hợp pháp đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi theo quy định của Bộ luật dân sự, người chưa đủ 14 tuổi; trường hợp không có bản sao thì nộp bản chụp và xuất trình bản chính để kiểm tra, đối chiếu.', '', 'Bản chính: 1Bản sao: 1', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (20, 'Bao gồm', 'Trường hợp nộp hồ sơ trực tuyến thì thành phần hồ sơ phải được chứng thực điện tử theo quy định, trường hợp hồ sơ chưa được chứng thực điện tử thì gửi hồ sơ về cơ quan tiếp nhận thông qua dịch vụ bưu chính công ích.', '', 'Bản chính: 0Bản sao: 0', '1.001456');
INSERT INTO rag.thanh_phan_ho_so VALUES (65, 'Đăng ký thường trú vào chỗ ở hợp pháp do thuê, mượn, ở nhờ', 'Hợp đồng, văn bản về việc cho thuê, cho mượn, cho ở nhờ được công chứng hoặc chứng thực theo quy định của pháp luật.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (21, '* Các trường hợp quy định tại khoản 4 Điều 15 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam đề nghị cấp hộ chiếu phổ thông ở trong nước lần đầu tại Cục Quản lý xuất nhập cảnh phải bổ sung một trong các loại hồ sơ, giấy tờ sau:', '+ Giấy giới thiệu hoặc đề nghị của bệnh viện về việc ra nước ngoài để khám, chữa bệnh;', '', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (22, '* Các trường hợp quy định tại khoản 4 Điều 15 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam đề nghị cấp hộ chiếu phổ thông ở trong nước lần đầu tại Cục Quản lý xuất nhập cảnh phải bổ sung một trong các loại hồ sơ, giấy tờ sau:', '+ Giấy tờ xác định thân nhân ở nước ngoài bị tai nạn, bệnh tật, bị chết;', '', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (23, '* Các trường hợp quy định tại khoản 4 Điều 15 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam đề nghị cấp hộ chiếu phổ thông ở trong nước lần đầu tại Cục Quản lý xuất nhập cảnh phải bổ sung một trong các loại hồ sơ, giấy tờ sau:', '+ Văn bản đề nghị của cơ quan trực tiếp quản lý đối với cán bộ, công chức, viên chức, sĩ quan, hạ sĩ quan, quân nhân chuyên nghiệp, công nhân, viên chức trong lực lượng vũ trang, người làm việc trong tổ chức cơ yếu;', '', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (24, '* Các trường hợp quy định tại khoản 4 Điều 15 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam đề nghị cấp hộ chiếu phổ thông ở trong nước lần đầu tại Cục Quản lý xuất nhập cảnh phải bổ sung một trong các loại hồ sơ, giấy tờ sau:', '+ Tài liệu chứng minh đối với các trường hợp vì lý do nhân đạo, khẩn cấp khác.', '', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (25, 'Bao gồm', '+ 02 ảnh mới chụp không quá 06 tháng, cỡ 4cm x6cm, mặt nhìn thẳng, đầu để trần, rõ mặt, rõ hai tai, không đeo kính, trang phục lịch sự, phông nền trắng.', '', 'Bản chính: 2Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (26, 'Bao gồm', '+ Hộ chiếu phổ thông cấp lần gần nhất đối với người đã được cấp hộ chiếu; trường hợp bị mất hộ chiếu, phải có đơn trình báo mất hộ chiếu hoặc thông báo về việc đã tiếp nhận đơn của cơ quan có thẩm quyền quy định tại Điều 28 Luật Xuất cảnh, nhập cảnh của công dân Việt Nam;', '', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (27, 'Bao gồm', '+ Bản chụp Chứng minh nhân dân hoặc Thẻ căn cước công dân đối với trường hợp có sự thay đổi thông tin về nhân thân so với thông tin trong hộ chiếu đã cấp lần gần nhất.', '', 'Bản chính: 1Bản sao: 1', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (28, 'Bao gồm', '+ Bản sao giấy khai sinh hoặc trích lục khai sinh đối với người chưa đủ 14 tuổi;', '', 'Bản chính: 0Bản sao: 1', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (29, 'Bao gồm', '+ Bản chụp có chứng thực giấy tờ do cơ quan có thẩm quyền của Việt Nam cấp chứng minh người đại diện hợp pháp đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi theo quy định của Bộ luật dân sự, người chưa đủ 14 tuổi; trường hợp bản chụp không có chứng thực thì xuất trình bản chính để kiểm tra đối chiếu.', '', 'Bản chính: 0Bản sao: 1', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (30, 'Bao gồm', 'Trường hợp nộp hồ sơ trực tuyến thì thành phần hồ sơ phải được chứng thực điện tử theo quy định, trường hợp hồ sơ chưa được chứng thực điện tử thì gửi hồ sơ về cơ quan tiếp nhận thông qua dịch vụ bưu chính công ích.', '', 'Bản chính: 1Bản sao: 1', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (31, 'Bao gồm', '* Số lượng hồ sơ: 01 (một) bộ.', '', 'Bản chính: 1Bản sao: 1', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (32, 'Bao gồm', '01 tờ khai đề nghị cấp hộ chiếu phổ thông (mẫu TK01) ban hành kèm theo Thông tư số 73/2021/TT-BCA ngày 29/6/2021 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức và làm chủ hành vi, người chưa đủ 14 tuổi, tờ khai do người đại diện hợp pháp khai, ký thay KHÔNG CẦN XÁC NHẬN CỦA CHÍNH QUYỀN ĐỊA PHƯƠNG (XÃ, PHƯỜNG, THỊ TRẤN NƠI CƯ TRÚ);', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MauTK01.tt73.2021.pdf', 'Bản chính: 1Bản sao: 0', '1.001471');
INSERT INTO rag.thanh_phan_ho_so VALUES (33, '* Gia hạn tạm trú theo danh sách, hồ sơ gồm:', '- Văn bản đề nghị gia hạn tạm trú trong đó ghi rõ thông tin về chỗ ở hợp pháp kèm danh sách người gia hạn tạm trú. Danh sách bao gồm những thông tin cơ bản của từng người: họ, chữ đệm và tên; ngày, tháng, năm sinh; giới tính; số định danh cá nhân và thời hạn tạm trú.', '', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (34, '* Gia hạn tạm trú theo danh sách, hồ sơ gồm:', 'Tờ khai thay đổi thông tin cư trú (của từng người) (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (35, '* Gia hạn tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (nơi đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', '- Đối với Công an nhân dân: Giấy giới thiệu của Thủ trưởng đơn vị quản lý trực tiếp ghi rõ nội dung để làm thủ tục gia hạn tạm trú và đơn vị có chỗ ở cho cán bộ chiến sĩ (ký tên, đóng dấu).', '', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (36, '* Gia hạn tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (nơi đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', '- Đối với Quân đội nhân dân: Giấy giới thiệu đăng ký thường trú của đơn vị cấp trung đoàn và tương đương trở lên.', '', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (37, '* Gia hạn tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (nơi đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', 'Tờ khai thay đổi thông tin cư trú (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (38, '* Hồ sơ gia hạn tạm trú gồm:', 'Tờ khai thay đổi thông tin cư trú (Mẫu CT01 ban hành kèm theo Thông tư số 53/2023/TT-BCA); trong đó ghi rõ ý kiến đồng ý của chủ sở hữu chỗ ở hợp pháp, trừ trường hợp đã có ý kiến đồng ý bằng văn bản. Đối với người gia hạn tạm trú là người chưa thành niên thì trong tờ khai phải ghi rõ ý kiến đồng ý của cha, mẹ hoặc người giám hộ, trừ trường hợp đã có ý kiến đồng ý bằng văn bản.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (39, 'Bao gồm', 'Lưu ý:- Trường hợp nộp hồ sơ trực tiếp tại cơ quan đăng ký cư trú thì người yêu cầu đăng ký cư trú có thể nộp bản sao giấy tờ, tài liệu được chứng thực từ bản chính hoặc bản sao giấy tờ được cấp từ sổ gốc (sau đây gọi là bản sao) hoặc bản quét, bản chụp kèm theo bản chính giấy tờ, tài liệu để đối chiếu. Trường hợp người yêu cầu đăng ký cư trú nộp bản quét hoặc bản chụp kèm theo bản chính giấy tờ để đối chiếu thì người tiếp nhận có trách nhiệm kiểm tra, đối chiếu bản quét, bản chụp với bản chính và ký xác nhận, không được yêu cầu nộp bản sao giấy tờ đó. - Trường hợp thực hiện đăng ký cư trú trực tuyến, người yêu cầu đăng ký cư trú khai báo thông tin theo biểu mẫu điện tử được cung cấp sẵn, đăng tải bản quét hoặc bản chụp giấy tờ, tài liệu hợp lệ (không bắt buộc phải công chứng, chứng thực, ký số hoặc xác thực bằng hình thức khác) hoặc dẫn nguồn tài liệu từ Kho quản lý dữ liệu điện tử của tổ chức, cá nhân. Trường hợp công dân đăng tải bản quét, bản chụp giấy tờ, tài liệu mà không được ký số hoặc xác thực bằng hình thức khác thì khi cơ quan đăng ký cư trú tiến hành kiểm tra, xác minh để giải quyết thủ tục về cư trú; công dân có trách nhiệm xuất trình giấy tờ, tài liệu đã đăng tải để cơ quan đăng ký cư trú kiểm tra, đối chiếu và ghi nhận tính chính xác vào biên bản xác minh. Cơ quan đăng ký cư trú không yêu cầu công dân nộp để lưu giữ giấy tờ đó. - Bản quét hoặc bản chụp giấy tờ bằng thiết bị điện tử từ giấy tờ được cấp hợp lệ, còn giá trị sử dụng phải bảo đảm rõ nét, đầy đủ, toàn vẹn về nội dung; đã được hợp pháp hóa lãnh sự, dịch sang tiếng Việt theo quy định nếu là giấy tờ do cơ quan có thẩm quyền nước ngoài cấp trừ trường hợp được miễn hợp pháp hóa lãnh sự. - Trường hợp thông tin giấy tờ chứng minh điều kiện đăng ký cư trú đã được chia sẻ và khai thác từ cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành thì cơ quan đăng ký cư trú không được yêu cầu công dân nộp, xuất trình giấy tờ đó để giải quyết đăng ký cư trú. - Khi hết thời hạn tạm trú, đại diện thành viên hộ gia đình được kê khai, đăng ký gia hạn tạm trú cho bản thân hoặc các thành viên khác trong hộ gia đình khi được chủ sở hữu chỗ ở hợp pháp đồng ý, không phải xuất trình, cung cấp giấy tờ chứng minh chỗ ở hợp pháp.', '', 'Bản chính: 1Bản sao: 1', '1.002755');
INSERT INTO rag.thanh_phan_ho_so VALUES (40, '- Trường hợp công dân thuộc quy định tại điểm a, điểm b khoản 1 Điều 31 Luật Cư trú, hồ sơ gồm:', '+ Đề nghị khai báo tạm vắng;', '', 'Bản chính: 1Bản sao: 0', '1.003677');
INSERT INTO rag.thanh_phan_ho_so VALUES (41, '- Trường hợp công dân thuộc quy định tại điểm a, điểm b khoản 1 Điều 31 Luật Cư trú, hồ sơ gồm:', '+ Văn bản đồng ý của cơ quan có thẩm quyền giám sát, quản lý, giáo dục người đó.', '', 'Bản chính: 1Bản sao: 0', '1.003677');
INSERT INTO rag.thanh_phan_ho_so VALUES (42, '- Trường hợp thuộc quy định tại điểm c, điểm d khoản 1 Điều 31 Luật Cư trú:', 'Nội dung khai báo tạm vắng gồm: họ và tên, số định danh cá nhân hoặc số Chứng minh nhân dân, số hộ chiếu của người khai báo tạm vắng; lý do tạm vắng; thời gian tạm vắng; địa chỉ nơi đến.', '', 'Bản chính: 1Bản sao: 1', '1.003677');
INSERT INTO rag.thanh_phan_ho_so VALUES (43, '* Hồ sơ đăng ký tạm trú gồm:', 'Tờ khai thay đổi thông tin cư trú (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA); đối với người đăng ký tạm trú là người chưa thành niên thì trong tờ khai phải ghi rõ ý kiến đồng ý của cha, mẹ hoặc người giám hộ, trừ trường hợp đã có ý kiến đồng ý bằng văn bản;', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (44, '* Hồ sơ đăng ký tạm trú gồm:', 'Thông tin chứng minh về chỗ ở hợp pháp được khai thác trong căn cước điện tử, tài khoản định danh điện tử trên hệ thống định danh và xác thực điện tử qua Ứng dụng định danh quốc gia hoặc trong Cơ sở dữ liệu quốc gia về dân cư, Cơ sở dữ liệu về cư trú, Kho quản lý dữ liệu điện tử tổ chức, cá nhân trên Cổng dịch vụ công quốc gia, Hệ thống thông tin giải quyết thủ tục hành chính cấp bộ, cấp tỉnh hoặc cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành khác. Trường hợp không khai thác được thông tin thì công dân xuất trình giấy tờ, tài liệu chứng minh chỗ ở hợp pháp theo quy định tại khoản 3 Điều 5 Nghị định 154/2024/NĐ-CP ngày 26/11/2024 của Chính phủ.', '', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (45, '* Hồ sơ đăng ký tạm trú gồm:', 'Ví dụ: Trường hợp giấy tờ, tài liệu chứng minh chỗ ở hợp pháp là giấy tờ, tài liệu chứng nhận về quyền sử dụng đất, quyền sở hữu tài sản gắn liền với đất do cơ quan có thẩm quyền cấp qua các thời kỳ theo quy định của pháp luật về đất đai và nhà ở được khai thác trong Cơ sở dữ liệu quốc gia về đất đai thì không phải xuất trình giấy tờ, tài liệu chứng minh chỗ ở hợp pháp.', '', 'Bản chính: 0Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (46, '* Đăng ký tạm trú theo danh sách, hồ sơ gồm:', 'Tờ khai thay đổi thông tin cư trú (của từng người) (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (47, '* Đăng ký tạm trú theo danh sách, hồ sơ gồm:', 'Văn bản đề nghị đăng ký tạm trú, trong đó ghi rõ thông tin về chỗ ở hợp pháp kèm danh sách người tạm trú. Danh sách bao gồm những thông tin cơ bản của từng người: họ, chữ đệm và tên; ngày, tháng, năm sinh; giới tính; số định danh cá nhân và thời hạn tạm trú.', '', 'Bản chính: 1Bản sao: 1', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (48, 'Đăng ký tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', 'Tờ khai thay đổi thông tin cư trú (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (49, 'Đăng ký tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', 'Đối với Công an nhân dân: Giấy giới thiệu của Thủ trưởng đơn vị quản lý trực tiếp ghi rõ nội dung để làm thủ tục đăng ký tạm trú và đơn vị có chỗ ở cho cán bộ chiến sĩ (ký tên, đóng dấu).', '', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (50, 'Đăng ký tạm trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân (đơn vị đóng quân, nhà ở công vụ) hồ sơ gồm:', 'Đối với Quân đội nhân dân: Giấy giới thiệu đăng ký tạm trú của đơn vị cấp trung đoàn và tương đương trở lên.', '', 'Bản chính: 1Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (51, 'Bao gồm', '*Lưu ý: - Trường hợp giấy tờ, tài liệu chứng minh chỗ ở hợp pháp để đăng ký tạm trú là văn bản cho thuê, cho mượn, cho ở nhờ nhà ở, nhà khác của cá nhân, tổ chức thì văn bản đó không bắt buộc phải công chứng hoặc chứng thực. - Người nước ngoài được nhập quốc tịch Việt Nam khi đăng ký tạm trú lần đầu phải có Quyết định của Chủ tịch nước về việc cho nhập quốc tịch Việt Nam. Người gốc Việt Nam được trở lại quốc tịch Việt Nam khi đăng ký tạm trú lần đầu sau khi được cho trở lại quốc tịch Việt Nam phải có Quyết định của Chủ tịch nước về việc cho trở lại quốc tịch Việt Nam trừ trường hợp đã khai thác được thông tin trong Cơ sở dữ liệu quốc tịch. - Công dân đăng ký tạm trú về với hộ gia đình thuộc trường hợp quy định tại khoản 2 Điều 20 Luật Cư trú khi chủ hộ, chủ sở hữu chỗ ở hợp pháp đồng ý và không phải xuất trình, cung cấp giấy tờ chứng minh chỗ ở hợp pháp. - Trong thời hạn tối đa 60 ngày kể từ ngày người chưa thành niên được đăng ký khai sinh thì phải thực hiện thủ tục đăng ký cư trú.', '', 'Bản chính: 0Bản sao: 0', '1.004194');
INSERT INTO rag.thanh_phan_ho_so VALUES (52, 'Người sinh sống, người làm nghề lưu động trên phương tiện được đăng ký thường trú tại phương tiện', 'Giấy chứng nhận đăng ký phương tiện và giấy chứng nhận an toàn kỹ thuật và bảo vệ môi trường của phương tiện hoặc văn bản xác nhận của Ủy ban nhân dân cấp xã về việc sử dụng phương tiện đó vào mục đích để ở đối với phương tiện không thuộc đối tượng phải đăng ký, đăng kiểm (nội dung xác nhận tại mục 2 của Ủy ban nhân dân cấp xã tại Tờ khai đề nghị xác nhận nơi thường xuyên đậu, đỗ; sử dụng phương tiện vào mục đích để ở theo Mẫu số 01 ban hành kèm theo Nghị định số 154/2024/NĐ-CP).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (53, 'Người sinh sống, người làm nghề lưu động trên phương tiện được đăng ký thường trú tại phương tiện', 'Văn bản xác nhận của Ủy ban nhân dân cấp xã về địa điểm phương tiện đăng ký đậu, đỗ thường xuyên trong trường hợp phương tiện không phải đăng ký hoặc nơi đăng ký phương tiện không trùng với nơi thường xuyên đậu, đỗ (nội dung xác nhận tại mục 1 của Ủy ban nhân dân cấp xã tại Tờ khai đề nghị xác nhận nơi thường xuyên đậu, đỗ; sử dụng phương tiện vào mục đích để ở theo Mẫu số 01 ban hành kèm theo Nghị định số 154/2024/NĐ-CP).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (54, 'Người được chăm sóc, nuôi dưỡng, trợ giúp được đăng ký thường trú tại cơ sở trợ giúp xã hội hoặc được đăng ký thường trú vào hộ gia đình nhận chăm sóc, nuôi dưỡng, trợ giúp', 'Văn bản đề nghị của người đứng đầu cơ sở trợ giúp xã hội đối với người được cơ sở trợ giúp xã hội nhận chăm sóc, nuôi dưỡng, trợ giúp.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (55, 'Người được chăm sóc, nuôi dưỡng, trợ giúp được đăng ký thường trú tại cơ sở trợ giúp xã hội hoặc được đăng ký thường trú vào hộ gia đình nhận chăm sóc, nuôi dưỡng, trợ giúp', 'Giấy tờ, tài liệu xác nhận về việc chăm sóc, nuôi dưỡng, trợ giúp.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (56, 'Đăng ký thường trú tại chỗ ở hợp pháp không thuộc quyền sở hữu của mình đối với những trường hợp quy định tại khoản 2 Điều 20 Luật Cư trú', 'Thông tin chứng minh quan hệ nhân thân với chủ hộ, thành viên hộ gia đình được khai thác trong căn cước điện tử, tài khoản định danh điện tử trên hệ thống định danh và xác thực điện tử qua Ứng dụng định danh quốc gia hoặc trong Cơ sở dữ liệu quốc gia về dân cư, Cơ sở dữ liệu về cư trú, Kho quản lý dữ liệu điện tử tổ chức, cá nhân trên Cổng dịch vụ công quốc gia, Hệ thống thông tin giải quyết thủ tục hành chính cấp bộ, cấp tỉnh hoặc cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành khác. Trường hợp không khai thác được thông tin thì công dân xuất trình giấy tờ, tài liệu chứng minh quan hệ nhân thân với chủ hộ, thành viên hộ gia đình theo quy định tại khoản 2, khoản 3 Điều 6 Nghị định 154/2024/NĐ-CP ngày 26/11/2024 của Chính phủ. Ví dụ: Trường hợp giấy tờ, tài liệu chứng minh quan hệ nhân thân với chủ hộ, thành viên hộ gia đình là giấy chứng nhận kết hôn, giấy xác nhận tình trạng hôn nhân, giấy khai sinh được khai thác trong Cơ sở dữ liệu hộ tịch điện tử thì không phải xuất trình giấy tờ, tài liệu chứng minh quan hệ nhân thân.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (57, 'Đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở', 'Trường hợp quy định tại điểm a, b, c khoản 4 Điều 20 Luật Cư trú đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ giúp là nhà ở, hồ sơ gồm:', '', 'Bản chính: 0Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (58, 'Đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở', 'Giấy tờ, tài liệu chứng minh là nhà tu hành, chức sắc, chức việc hoặc người khác hoạt động tôn giáo và được hoạt động tại cơ sở tôn giáo đó theo quy định của pháp luật về tín ngưỡng, tôn giáo đối với người quy định tại điểm a khoản 4 Điều 20 Luật Cư trú; giấy tờ, tài liệu chứng minh là người đại diện cơ sở tín ngưỡng đối với người quy định tại điểm b khoản 4 Điều 20 Luật Cư trú.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (59, 'Đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở', 'Văn bản xác nhận của Ủy ban nhân dân cấp xã về việc trong cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (60, 'Đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở', 'Trường hợp quy định tại điểm d khoản 4 Điều 20 Luật Cư trú đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ giúp là nhà ở, hồ sơ gồm:', '', 'Bản chính: 0Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (61, 'Đăng ký thường trú tại cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở', 'Văn bản xác nhận của Ủy ban nhân dân cấp xã về việc người đăng ký thường trú thuộc đối tượng quy định tại khoản 2 Điều 17 Luật Cư trú và việc trong cơ sở tín ngưỡng, cơ sở tôn giáo có công trình phụ trợ là nhà ở.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (62, 'Đăng ký thường trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân nhân (đơn vị đóng quân, nhà ở công vụ)', 'Tờ khai thay đổi thông tin cư trú (mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (63, 'Đăng ký thường trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân nhân (đơn vị đóng quân, nhà ở công vụ)', 'Đối với Công an nhân dân: Giấy giới thiệu của Thủ trưởng đơn vị quản lý trực tiếp ghi rõ nội dung để làm thủ tục đăng ký thường trú và đơn vị có chỗ ở cho cán bộ chiến sĩ (ký tên, đóng dấu).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (64, 'Đăng ký thường trú tại nơi đơn vị đóng quân trong Công an nhân dân, Quân đội nhân nhân nhân (đơn vị đóng quân, nhà ở công vụ)', 'Đối với Quân đội nhân dân: Giấy giới thiệu đăng ký thường trú của cơ quan, đơn vị cấp trung đoàn và tương đương trở lên (ký tên, đóng dấu).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (66, 'Đăng ký thường trú vào chỗ ở hợp pháp do thuê, mượn, ở nhờ', 'Thông tin chứng minh đủ diện tích nhà ở để đăng ký thường trú tại chỗ ở hợp pháp do thuê, mượn, ở nhờ được khai thác trong căn cước điện tử, tài khoản định danh điện tử trên hệ thống định danh và xác thực điện tử qua Ứng dụng định danh quốc gia hoặc trong Cơ sở dữ liệu quốc gia về dân cư, Cơ sở dữ liệu về cư trú, Kho quản lý dữ liệu điện tử tổ chức, cá nhân trên Cổng dịch vụ công quốc gia, Hệ thống thông tin giải quyết thủ tục hành chính cấp bộ, cấp tỉnh hoặc cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành khác. Trường hợp không khai thác được thông tin thì công dân xuất trình giấy tờ, tài liệu quy định tại khoản 2 Điều 5 Nghị định số 154/2024/NĐ-CP, trong đó có thể hiện diện tích nhà ở hoặc xác nhận của Ủy ban nhân dân cấp xã về điều kiện diện tích bình quân bảo đảm theo quy định của Hội đồng nhân dân tỉnh, thành phố trực thuộc trung ương theo Mẫu số 02 ban hành kèm theo Nghị định số 154/2024/NĐ-CP. Ví dụ: Trường hợp giấy tờ, tài liệu chứng minh đủ diện tích nhà ở để đăng ký thường trú theo quy định là giấy tờ, tài liệu chứng nhận về quyền sử dụng đất, quyền sở hữu tài sản gắn liền với đất do cơ quan có thẩm quyền cấp qua các thời kỳ theo quy định của pháp luật về đất đai và nhà ở được khai thác trong Cơ sở dữ liệu quốc gia về đất đai thì không phải xuất trình giấy tờ, tài liệu chứng minh đủ diện tích nhà ở.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (67, 'Đăng ký thường trú vào chỗ ở hợp pháp thuộc quyền sở hữu của mình', 'Tờ khai thay đổi thông tin cư trú (mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA) hoặc Tờ khai thay đổi thông tin về cư trú dùng cho công dân Việt Nam định cư ở nước ngoài không có hộ chiếu Việt Nam còn giá trị sử dụng (mẫu CT02 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (68, 'Đăng ký thường trú vào chỗ ở hợp pháp thuộc quyền sở hữu của mình', 'Thông tin chứng minh về chỗ ở hợp pháp được khai thác trong căn cước điện tử, tài khoản định danh điện tử trên hệ thống định danh và xác thực điện tử qua Ứng dụng định danh quốc gia hoặc trong Cơ sở dữ liệu quốc gia về dân cư, Cơ sở dữ liệu về cư trú, Kho quản lý dữ liệu điện tử tổ chức, cá nhân trên Cổng dịch vụ công quốc gia, Hệ thống thông tin giải quyết thủ tục hành chính cấp bộ, cấp tỉnh hoặc cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành khác. Trường hợp không khai thác được thông tin thì công dân xuất trình giấy tờ, tài liệu chứng minh chỗ ở hợp pháp theo quy định tại khoản 2 Điều 5 Nghị định 154/2024/NĐ-CP ngày 26/11/2024 của Chính phủ. Ví dụ: Trường hợp giấy tờ, tài liệu chứng minh chỗ ở hợp pháp là giấy tờ, tài liệu chứng nhận về quyền sử dụng đất, quyền sở hữu tài sản gắn liền với đất do cơ quan có thẩm quyền cấp qua các thời kỳ theo quy định của pháp luật về đất đai và nhà ở được khai thác trong Cơ sở dữ liệu quốc gia về đất đai thì không phải xuất trình giấy tờ, tài liệu chứng minh chỗ ở hợp pháp.', '', 'Bản chính: 1Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (69, 'Bao gồm', '*Lưu ý: - Không yêu cầu xuất trình Giấy khai sinh đối với trường hợp trẻ em mới sinh đăng ký thường trú lần đầu. - Trong thời hạn tối đa 60 ngày kể từ ngày người chưa thành niên được đăng ký khai sinh thì phải thực hiện thủ tục đăng ký cư trú. - Trường hợp người cao tuổi, người chưa thành niên đã có thông tin về ngày, tháng, năm sinh trong Cơ sở dữ liệu quốc gia về dân cư thì không yêu cầu xuất trình giấy tờ chứng minh. - Trường hợp công dân đăng ký thường trú vào chỗ ở hợp pháp thuộc quyền sở hữu của mình mà chỗ ở hợp pháp đó có nhiều hơn một chủ sở hữu thì không cần có ý kiến đồng ý của những người đồng sở hữu. - Trường hợp đăng ký thường trú theo quy định tại điểm a khoản 2 Điều 20 Luật Cư trú mà chỗ ở hợp pháp có nhiều hơn một chủ sở hữu thì chỉ cần ý kiến đồng ý của ít nhất một chủ sở hữu. - Trường hợp đăng ký thường trú vào chỗ ở hợp pháp của chủ sở hữu là người bị mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi theo quy định của Bộ luật Dân sự, người dưới 18 tuổi, người bị tuyên bố mất tích, người đã chết thì chỉ cần lấy ý kiến đồng ý của một trong những người đại diện hợp pháp, người thừa kế của chủ sở hữu theo quy định của pháp luật. - Người có mối quan hệ với chủ sở hữu chỗ ở hợp pháp theo quy định tại điểm a khoản 2 Điều 20 Luật Cư trú mà đăng ký thường trú vào chỗ ở chưa có hộ gia đình đăng ký thường trú và không thuộc trường hợp quy định tại Điều 23 Luật Cư trú hoặc người đăng ký thường trú có mối quan hệ với chủ hộ, thành viên hộ gia đình theo quy định tại điểm a khoản 2 Điều 20 Luật Cư trú mà nơi thường trú của chủ hộ, thành viên hộ gia đình đó là chỗ ở hợp pháp do thuê, mượn, ở nhờ thì hồ sơ đăng ký thường trú thực hiện theo khoản 2 Điều 21 Luật Cư trú. - Người đăng ký thường trú theo điều kiện quy định tại điểm a khoản 2 Điều 20 Luật Cư trú mà chỗ ở đăng ký thường trú là địa điểm quy định tại Điều 23 Luật Cư trú thì hồ sơ đăng ký thường trú không cần phải có ý kiến đồng ý của chủ sở hữu chỗ ở hợp pháp đó trong trường hợp không xác định được chủ sở hữu. - Trường hợp người đăng ký thường trú là người Việt Nam định cư ở nước ngoài còn quốc tịch Việt Nam thì trong hồ sơ đăng ký thường trú phải có hộ chiếu Việt Nam còn giá trị sử dụng; trường hợp không có hộ chiếu Việt Nam còn giá trị sử dụng thì phải có giấy tờ, tài liệu chứng minh có quốc tịch Việt Nam theo quy định của pháp luật Việt Nam về quốc tịch và văn bản đồng ý cho giải quyết thường trú của cơ quan quản lý xuất nhập cảnh của Bộ Công an. - Trường hợp người nước ngoài được nhập quốc tịch Việt Nam khi đăng ký thường trú lần đầu phải có Quyết định của Chủ tịch nước về việc cho nhập quốc tịch Việt Nam. Người gốc Việt Nam được trở lại quốc tịch Việt Nam khi đăng ký thường trú lần đầu sau khi được cho trở lại quốc tịch Việt Nam phải có Quyết định của Chủ tịch nước về việc cho trở lại quốc tịch Việt Nam trừ trường hợp đã khai thác được thông tin trong Cơ sở dữ liệu quốc tịch. - Sĩ quan nghiệp vụ, hạ sĩ quan nghiệp vụ, sĩ quan chuyên môn kỹ thuật, hạ sĩ quan chuyên môn kĩ thuật, công nhân công an đã đăng ký thường trú tại đơn vị đóng quân mà chuyển đến chỗ ở hợp pháp mới ngoài đơn vị đóng quân và đủ điều kiện đăng ký thường trú, đề nghị đăng ký thường trú tại chỗ ở mới thì hồ sơ đăng ký thường trú phải kèm Giấy giới thiệu của Thủ trưởng đơn vị quản lý trực tiếp (ký tên và đóng dấu). - Sĩ quan, quân nhân chuyên nghiệp, công nhân, viên chức quốc phòng đã đăng ký thường trú vào nhà ở công vụ, đơn vị đóng quân khi chuyển đăng ký thường trú ra chỗ ở hợp pháp ngoài nơi nhà ở công vụ, nơi đơn vị đóng quân thì hồ sơ đăng ký thường trú tại chỗ ở mới phải kèm theo Giấy giới thiệu đăng ký thường trú của đơn vị đang công tác (ký tên và đóng dấu).', '', 'Bản chính: 0Bản sao: 0', '1.004222');
INSERT INTO rag.thanh_phan_ho_so VALUES (70, 'Bao gồm', '+ Hộ chiếu phổ thông còn nguyên vẹn và có thị thực do nước ngoài cấp còn thời hạn.', '', 'Bản chính: 1Bản sao: 0', '1.010382');
INSERT INTO rag.thanh_phan_ho_so VALUES (71, 'Bao gồm', 'Trường hợp nộp hồ sơ trực tuyến thì thành phần hồ sơ phải được chứng thực điện tử theo quy định, trường hợp hồ sơ chưa được chứng thực điện tử thì gửi hồ sơ về cơ quan tiếp nhận thông qua dịch vụ bưu chính công ích.', '', 'Bản chính: 1Bản sao: 1', '1.010382');
INSERT INTO rag.thanh_phan_ho_so VALUES (72, 'Bao gồm', '+ Tờ khai đề nghị khôi phục giá trị sử dụng hộ chiếu phổ thông (mẫu TK04) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an; đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai, ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK04khôiphụcHCTK04MỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.010382');
INSERT INTO rag.thanh_phan_ho_so VALUES (73, 'Bao gồm', 'Tờ khai đề nghị khôi phục giá trị sử dụng hộ chiếu phổ thông (mẫu TK04) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, người có khó khăn trong nhận thức, làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai, ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK04khôiphụcHCTK04MỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.010384');
INSERT INTO rag.thanh_phan_ho_so VALUES (74, 'Bao gồm', 'Hộ chiếu phổ thông còn nguyên vẹn và có thị thực do nước ngoài cấp còn thời hạn.', '', 'Bản chính: 1Bản sao: 0', '1.010384');
INSERT INTO rag.thanh_phan_ho_so VALUES (75, 'Bao gồm', 'Trường hợp nộp hồ sơ trực tuyến thì thành phần hồ sơ phải được chứng thực điện tử theo quy định, trường hợp hồ sơ chưa được chứng thực điện tử thì gửi hồ sơ về cơ quan tiếp nhận thông qua dịch vụ bưu chính công ích.', '', 'Bản chính: 0Bản sao: 0', '1.010384');
INSERT INTO rag.thanh_phan_ho_so VALUES (76, 'Bao gồm', '01 đơn trình báo mất hộ chiếu phổ thông (mẫu TK05) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, có khó khăn trong nhận thức và làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai và ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK05báomấtHC057TK05MỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.010385');
INSERT INTO rag.thanh_phan_ho_so VALUES (77, 'Bao gồm', '01 đơn trình báo mất hộ chiếu phổ thông (mẫu TK05) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2023 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, có khó khăn trong nhận thức và làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai và ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK05báomấtHC057TK05MỚI.pdf', 'Bản chính: 1Bản sao: 0', '1.010386');
INSERT INTO rag.thanh_phan_ho_so VALUES (78, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.000200');
INSERT INTO rag.thanh_phan_ho_so VALUES (79, 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an). Phiếu này là biểu mẫu điện tử, công dân kê khai đối với trường hợp nộp hồ sơ trực tuyến', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.000200');
INSERT INTO rag.thanh_phan_ho_so VALUES (80, 'Trường hợp công dân chưa có thông tin trong cơ sở dữ liệu quốc gia về dân cư thì hồ sơ còn có:', 'Phiếu thu thập thông tin dân cư (mẫu DC01 ban hành kèm theo Thông tư số 53/2025/TT-BCA ngày 01/7/2025 của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC01Phiếuthuthậpthôngtindâncư.pdf', 'Bản chính: 1Bản sao: 0', '2.000200');
INSERT INTO rag.thanh_phan_ho_so VALUES (81, 'Trường hợp công dân chưa có thông tin trong cơ sở dữ liệu quốc gia về dân cư thì hồ sơ còn có:', 'Giấy tờ pháp lý chứa thông tin công dân', '', 'Bản chính: 1Bản sao: 0', '2.000200');
INSERT INTO rag.thanh_phan_ho_so VALUES (82, 'Bao gồm', 'Đơn trình báo mất hộ chiếu phổ thông (mẫu TK05) ban hành kèm theo Thông tư số 31/2023/TT-BCA ngày 20/7/2022 của Bộ Công an. Đối với người mất năng lực hành vi dân sự, có khó khăn trong nhận thức và làm chủ hành vi, người chưa đủ 14 tuổi thì người đại diện hợp pháp khai và ký thay.', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuTK05báomấtHC057TK05MỚI.pdf', 'Bản chính: 1Bản sao: 0', '2.000539');
INSERT INTO rag.thanh_phan_ho_so VALUES (83, 'Bao gồm', 'Khi có người đến lưu trú, đại diện hộ gia đình, cơ sở khám bệnh, chữa bệnh, cơ sở lưu trú du lịch, cơ sở lưu trú ở khu công nghiệp, cơ sở khác có chức năng lưu trú thì phải thực hiện việc thông báo lưu trú cho người đang lưu trú theo một trong các hình thức đã được quy định tại và theo quy định sau đây: - Chủ hộ hoặc thành viên hộ gia đình, đại diện cơ sở lưu trú ở khu công nghiệp, cơ sở lưu trú du lịch đề nghị người đến lưu trú xuất trình một trong các giấy tờ pháp lý thể hiện thông tin về số định danh cá nhân theo quy định của pháp luật và thực hiện việc thông báo lưu trú với cơ quan đăng ký cư trú; - Đại diện cơ sở khám bệnh, chữa bệnh có trách nhiệm lập danh sách người đến điều trị nội trú và thực hiện thông báo lưu trú với cơ quan đăng ký cư trú nơi đặt trụ sở cơ sở khám chữa bệnh', '', 'Bản chính: 1Bản sao: 0', '2.001159');
INSERT INTO rag.thanh_phan_ho_so VALUES (84, 'Bao gồm', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.001178');
INSERT INTO rag.thanh_phan_ho_so VALUES (85, 'Bao gồm', 'Giấy chứng minh nhân dân 09 số (nếu có).', '', 'Bản chính: 1Bản sao: 0', '2.001178');
INSERT INTO rag.thanh_phan_ho_so VALUES (86, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.001194');
INSERT INTO rag.thanh_phan_ho_so VALUES (87, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.001194');
INSERT INTO rag.thanh_phan_ho_so VALUES (88, 'Trường hợp người đề nghị cấp, cấp đổi, cấp lại thẻ căn cước là người đại diện hợp pháp của người dưới 14 tuổi thì hồ sơ đề nghị cấp, cấp đổi, cấp lại thẻ căn cước phải có giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi.', 'Giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi', '', 'Bản chính: 1Bản sao: 0', '2.001194');
INSERT INTO rag.thanh_phan_ho_so VALUES (89, 'Phiếu được tạo lập khi trích xuất thông tin của công dân trong Cơ sở dữ liệu quốc gia về dân cư và in trong quá trình thu nhận hồ sơ căn cước để công dân kiểm tra và ký xác nhận.', 'Phiếu thu nhận thông tin căn cước (Mẫu CC01 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuCC01Phiếuthunhậnthôngtincăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.001195');
INSERT INTO rag.thanh_phan_ho_so VALUES (90, 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an). Phiếu này là biểu mẫu điện tử, công dân kê khai đối với trường hợp nộp hồ sơ trực tuyến.', 'Phiếu đề nghị giải quyết thủ tục về căn cước (Mẫu DC02 ban hành kèm theo Thông tư số 17/2024/TT-BCA của Bộ Công an)', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/MẫuDC02Phiếuđềnghịgiảiquyếtthủtụcvềcăncước.pdf', 'Bản chính: 1Bản sao: 0', '2.001195');
INSERT INTO rag.thanh_phan_ho_so VALUES (91, 'Trường hợp người đề nghị cấp, cấp đổi, cấp lại thẻ căn cước là người đại diện hợp pháp của người dưới 14 tuổi thì hồ sơ đề nghị cấp, cấp đổi, cấp lại thẻ căn cước phải có giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi', 'Giấy tờ, tài liệu có giá trị pháp lý chứng minh là người đại diện hợp pháp của người dưới 14 tuổi', '', 'Bản chính: 1Bản sao: 0', '2.001195');
INSERT INTO rag.thanh_phan_ho_so VALUES (92, 'Bao gồm', 'Tờ khai thay đổi thông tin cư trú (Mẫu CT01 ban hành kèm theo Thông tư số 53/2025/TT-BCA).', 'https://proceduces-forms.s3.ap-southeast-2.amazonaws.com/1.MuCT01banhnhkmtheoThngts53.pdf', 'Bản chính: 1Bản sao: 0', '1.010028');
INSERT INTO rag.thanh_phan_ho_so VALUES (93, 'Bao gồm', 'Thông tin chứng minh thuộc trường hợp xóa đăng ký tạm trú của công dân trong Cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành và cơ sở dữ liệu khác được kết nối, chia sẻ với cơ quan đăng ký cư trú. Trường hợp thông tin chưa được kết nối, chia sẻ thì công dân xuất trình giấy tờ, tài liệu chứng minh thuộc một trong các trường hợp xóa đăng ký tạm trú quy định tại Điều 29 Luật Cư trú.', '', 'Bản chính: 1Bản sao: 0', '1.010028');


